INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-014 CARBINE AIRSOFT RIFLE BLACK', 'AMOEBA', 249, 'https://www.arsenalsports.com/img/8345/produtos/600/9a84e8094d204d5841d57a8f7f90c6e6.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'O fuzil de asHop Up AM-014 emprega um novo design de foregrip para adaptar o método de tiro de rifle moderno, bem como sistema de trilho modular leve que permite uma ampla gama de acessórios opcionais, como luzes e lasers. O sistema de controle de disparo eletrônico de 3ª geração melhorado (EFCS) pode resistir a uma corrente de disparo de 30A e fornecer uma melhor posição do ciclo do pistão, o que garante uma velocidade de queima mais estável e prolonga a longevidade da mola.', 'https://www.arsenalsports.com/produto/-amoeba-aeg-m4-am014-carbine-airsoft-rifle-black-8345.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SILENCER 235MM QUICK DETACH 14MM CW LONG FOR MSR BLACK', 'AMOEBA', 35, 'https://www.arsenalsports.com/img/7770/produtos/600/bc19df05e44a443ce7465b6d68053347.jpg', (SELECT id FROM public.categories WHERE slug = 'snipers'), 'AEG', 'Diametro: 38mm
Se encaixa no cano com flashhiders direto ( Quick detach mechanism that fit direct with flash hider )
Marcações gravadas
Toda a construção metálica
Especifico para Sniper FH-MSR-01
Comprimento: 235mm
Peso: 250g

Nota:
Este é um supressor falso, e não-funciona
Não usar em armas reais, pois pode explodir
Use somente em airsoft, não vai diminuir o som.', 'https://www.arsenalsports.com/produto/amoeba-silencer-235mm-quick-detach-14mm-cw-long-for-msr-black-7770.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 MUTANT AMM13 AIRSOFT RIFLE BLACK', 'AMOEBA', 219, 'https://www.arsenalsports.com/img/17958/produtos/600/33bf82b4dc3e67a2ac834ff636f97f32.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Tipo AEG. GearBox EFCS. Material de fibra de nylon, alumínio, metal. Tipo de Disparo: Fire Mode Totalmente Automático / Semi Auto / Seguro. Material da GearBox liga de zine fundido. Hop-Up ajustável. Magazine: 140 Rounds. Liberação Rápida de Mola. Tipos de bateria: 7,4v - 11,1v. Peso 2620g. Comprimento 820-900mm. VEM COM 01 MAGAZINE 140 ROUNDS MID-CAP.', 'https://www.arsenalsports.com/produto/-amoeba-aeg-m4-mutant-amm13-airsoft-rifle-black-17958.html', true, 25, 20, 3);
