INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('TARAN TACTICAL EMG STI ARMORER WORKS GBB HI-CAPA 2011 DVC 3-GUN BLOWBACK AIRSOFT PISTOL BLACK', 'TARAN TACTICAL', 155, 'https://www.arsenalsports.com/img/15482/produtos/600/3d9c4944e9a09cf18583b262aabaeae5.png', (SELECT id FROM public.categories WHERE slug = 'pistolas'), 'GBB', 'O STI DVC 3-GUN foi projetado especificamente para atender às necessidades dos entusiastas atuais de 3 canhões, mantendo-se fiel à herança de precisão, potência e velocidade da Diligenta, Vis, Celeritas. Atire mais suavemente. Dispare mais tempo entre as recargas. Considere o desempenho parte crítica da arma do seu arsenal de 3 pistolas devidamente coberta.', 'https://www.arsenalsports.com/produto/-taran-tactical-emg-sti-armorer-works-gbb-hicapa-2011-dvc-3gun-blowback-airsoft-pistol-black-15482.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('TARAN TACTICAL JAG PRECISION ARMY ARMAMENT GBB HI-CAPA JW4 TTI PIT VIPER CNC BLOWBACK AIRSOFT PISTOL BLACK', 'TARAN TACTICAL', 156, 'https://www.arsenalsports.com/img/25445/produtos/600/9f9c6cdf3256650b0e6444ea61c98585.png', (SELECT id FROM public.categories WHERE slug = 'pistolas'), 'GBB', 'A Army Armament John Wick 4 Taran Tactical Pit Viper é uma pistola de airsoft totalmente licenciada inspirada na arma de fogo usada no filme "John Wick". Ele oferece uma experiência de disparo autêntica e foi projetado tendo em mente a velocidade e o tiro competitivo. As superfícies de controle ampliadas garantem acesso rápido e fácil, e os dispositivos de segurança ambidestros aumentam a versatilidade da pistola.', 'https://www.arsenalsports.com/produto/-taran-tactical-jag-precision-army-armament-gbb-hicapa-jw4-tti-pit-viper-cnc-blowback-airsoft-pistol-black-25445.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('TARAN TACTICAL JAG PRECISION ARMY ARMAMENT GBB HI-CAPA JW4 TTI PIT VIPER STANDARD BLOWBACK AIRSOFT PISTOL BLACK', 'TARAN TACTICAL', 129, 'https://www.arsenalsports.com/img/25446/produtos/600/05283d78a7f936cf227747109b697bdc.png', (SELECT id FROM public.categories WHERE slug = 'pistolas'), 'GBB', 'A Army Armament John Wick 4 Taran Tactical Pit Viper é uma pistola de airsoft totalmente licenciada inspirada na arma de fogo usada no filme ''John Wick''. Ele oferece uma experiência de disparo autêntica e foi projetado tendo em mente a velocidade e o tiro competitivo. As superfícies de controle ampliadas garantem acesso rápido e fácil, e os dispositivos de segurança ambidestros aumentam a versatilidade da pistola. Uma característica marcante desta pistola é sua excelente ergonomia e manuseio, começando pelo pontilhado de alta qualidade no punho. O Pit Viper também possui uma placa RMR, permitindo aos usuários montar sua ótica preferida na pistola, e o ferrolho é construído em metal, garantindo durabilidade e acabamento de alta qualidade.', 'https://www.arsenalsports.com/produto/-taran-tactical-jag-precision-army-armament-gbb-hicapa-jw4-tti-pit-viper-standard-blowback-airsoft-pistol-black-25446.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('A&K AEG MASADA LONG ACR ADAPTIVE COMBAT AIRSOFT RIFLE BLACK', 'A&K', 269, 'https://www.arsenalsports.com/img/27410/produtos/600/f99569bdcfbc6834f91fe50e90e3d5bc.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Receptor inferior de polímero de alta resistência. Receptor superior de liga de metal. Conjunto de cano totalmente metálico com HandGuard RIS estilo ACR totalmente metálico. Coronha retrátil/dobrável multiposição com suporte de bochecha ajustável. Controle de tiro ambidestro. Trilho superior de 20 mm de comprimento total com miras pretas dianteiras e traseiras. O batente de ferrolho simulado funcional permite fácil ajuste de hop up.', 'https://www.arsenalsports.com/produto/ak-aeg-masada-long-acr-adaptive-combat-airsoft-rifle-black-27410.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('TARAN TACTICAL JAG PRECISION ARMY ARMAMENT GBB HI-CAPA JW4 TTI SAND VIPER CNC BLOWBACK AIRSOFT PISTOL BRONZE', 'TARAN TACTICAL', 166, 'https://www.arsenalsports.com/img/25448/produtos/600/d04d645fb3b40e7316b6375c51a99306.png', (SELECT id FROM public.categories WHERE slug = 'pistolas'), 'GBB', 'A Army Armament John Wick 4 Taran Tactical Sand Viper é uma pistola de airsoft totalmente licenciada inspirada na arma de fogo usada no filme ''John Wick 4''. Ele oferece uma experiência de disparo autêntica e foi projetado tendo em mente a velocidade e o tiro competitivo. As superfícies de controle ampliadas garantem acesso rápido e fácil, e os dispositivos de segurança ambidestros aumentam a versatilidade da pistola. Uma característica marcante desta pistola é sua excelente ergonomia e manuseio, começando pelo pontilhado de alta qualidade no punho. O Sand Viper também possui uma placa RMR, permitindo aos usuários montar sua ótica preferida na pistola. O ferrolho da pistola é construído em alumínio CNC, garantindo durabilidade e acabamento de alta qualidade.', 'https://www.arsenalsports.com/produto/-taran-tactical-jag-precision-army-armament-gbb-hicapa-jw4-tti-sand-viper-cnc-blowback-airsoft-pistol-bronze-25448.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('A&K AEG MASADA LONG CARBINE ADAPTIVE COMBAT AIRSOFT RIFLE BLACK', 'A&K', 269, 'https://www.arsenalsports.com/img/27407/produtos/600/ed37b8d4a8b26c553c45f33f7d8ec9bb.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Receptor superior de metal, receptor inferior de polímero de alto impacto. Estoque retrátil e dobrável de múltiplas posições. Miras dianteiras e traseiras rebatíveis (a mira traseira é removível). Receptor Full Railed Flat Top Upper para acessórios ópticos. Descanso de bochecha ajustável. Liberação magnética ambidestra, liberação de parafuso e chave seletora. Pontos de fixação QD Sling Swivel integrados (QD Sling Swivel não incluído).', 'https://www.arsenalsports.com/produto/ak-aeg-masada-long-carbine-adaptive-combat-airsoft-rifle-black-27407.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('A&K AEG MASADA LONG DMR ADAPTIVE COMBAT AIRSOFT RIFLE BLACK', 'A&K', 269, 'https://www.arsenalsports.com/img/27419/produtos/600/1d20d354482e576f714fc071de99785f.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Receptor inferior de polímero de alta resistência. Receptor superior de liga de metal. Conjunto de cano totalmente de metal. Sistema de cano QD. HandGuard DMR estendido e coronha de rifle de precisão. Elevador de bochecha ajustável e almofada de coronha. Chave seletora ambidestra, liberação do carregador e liberação do ferrolho. Miras de backup dianteiras e traseiras dobráveis. Comprimento: 980mm / 1005mm. Peso total: 3280g. Material: Metal, Polímero de Alto Impacto. Comprimento do cano interno: 400 mm. Capacidade do Magazine: 300 Rounds Hi-Cap. Compatível com magazines da série M4/M16. Motor: Long Type. GearBox: Ver. 2 com 7mm. Totalmente atualizável, compatível com Tokyo Marui. Bateria: 9,6v 1600mAh. Hop-up: Sim, Ajustável. Modo de disparo: Safe, Semi-Auto, Full-Auto.', 'https://www.arsenalsports.com/produto/ak-aeg-masada-long-dmr-adaptive-combat-airsoft-rifle-black-27419.html', true, 25, 20, 3);
