INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('A&K GBBR M1873 Winchester Lever Action Short Type with M-Lock Rail Airsoft Rifle Wood & Black', 'A&K', 213, 'https://www.arsenalsports.com/img/30540/produtos/600/535507c186543952096e9f3c5ee2fce6.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'GBB', 'Crown made of solid wood with a metal receiver and forend assembly. Top Picatinny RIS mount allows for mounting optical sights, lasers, and other accessories. M-LOK slots around the HandGuard provide ample space for grips, flashlights, and other M-LOK compatible accessories you desire. Internal components/gas system in metal, metal tube and retention lever. Integrated safety ring for secure transport. Extended retention lever for ease of use with glasses. Internal capacity for up to 25 Rounds and integrated Gas Chamber in the body of the Rifle.', 'https://www.arsenalsports.com/produto/ak-gbbr-m1873-winchester-lever-action-short-type-with-mlock-rail-airsoft-rifle-wood--black-30540.html', true, 25, 20, 3);
