INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('A&K GBBR M1873 Winchester Lever Action Short Type with M-LOCK Rail Airsoft Rifle Wood & Gold', 'A&K', 213, 'https://www.arsenalsports.com/img/30541/produtos/600/e0012693ae468e94560bbaf5e3e4b1df.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'GBB', 'Coronha de madeira real com receptor de metal e conjunto de cano. O RIS picatinny superior permite a fixação de óticas, lasers e outros acessórios. Os slots M-LOK ao redor do HandGuard oferecem bastante espaço para empunhaduras, luzes e quaisquer outros acessórios compatíveis com M-LOK que você desejar! Peças internas de metal/sistema de gás, cano construído em metal e alça de alavanca D. Almofada de coronha de latão de alta qualidade. Anel de cordão integrado para transporte seguro. Alça de alavanca ampliada para uso fácil com luvas.', 'https://www.arsenalsports.com/produto/ak-gbbr-m1873-winchester-lever-action-short-type-with-mlock-rail-airsoft-rifle-wood--gold-30541.html', true, 25, 20, 3);
