INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('A&K SPRING SVD DRAGUNOV WITH METAL GEARBOX AND WOOD SNIPER AIRSOFT RIFLE', 'A&K', 195, 'https://www.arsenalsports.com/img/27550/produtos/600/8c2407e116ee93f110fbdd216a877e45.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'Construção totalmente metálica. Barril totalmente em metal, receptor e tudo mais que deveria ser de metal. Protetor de bochecha de atirador ajustável. Visão traseira ajustável. Seleção de fogo totalmente automática e semiautomática. Hop-Up Ajustável. Compartimento de bateria realista e discreto, pode precisar de assistência de ferramenta para abrir o compartimento da bateria. Cobertura contra poeira tratada com fosfato. Polímero com acabamento de imitação de madeira.

Especificações: Comprimento: 1219mm; Peso: 3500g; Capacidade do Magazine: 180 rodadas - Mid-Cap; Motor: Short Type; Hop-Up: Sim, Ajustável.', 'https://www.arsenalsports.com/produto/ak-spring-svd-dragunov-with-metal-gearbox-and-wood-sniper-airsoft-rifle-27550.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('ACEBEAM FLASHLIGHT LED 2200L / 1083M', 'ACEBEAM', 136, 'https://www.arsenalsports.com/img/31479/produtos/600/70701f31b8977b3a7f67c2ff217a72be.png', (SELECT id FROM public.categories WHERE slug = 'acessorios'), 'AEG', 'A lanterna ACEBEAM L19 2.0 é o equipamento definitivo para sua próxima viagem de caça ou aventura ao ar livre. Esta lanterna atualizada fornece até 2200 lúmens com uma distância de feixe impressionante de 3.553 pés (1.083 metros) — mais de meia milha! Ela se destaca como a lanterna de caça de maior alcance em sua classe com um diâmetro de cabeça de 55 mm. Os caçadores apreciarão a opção de LED verde, que preserva a visão noturna e minimiza o risco de assustar a presa. Apresentando uma classificação à prova d''água IP68 e alimentada por uma bateria de íons de lítio recarregável 21700, a L19 2.0 foi construída para aqueles que exigem distância de feixe extrema e durabilidade robusta. Luminus SFT40 HI 6500K Max Output: 2200lumens/1083Meters/293222cd. Bateira: 1 x IMR21700NP-510A USB-C Charging.', 'https://www.arsenalsports.com/produto/acebeam-flashlight-led-2200l--1083m-31479.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('ACTION ARMY GBB AAP01 ASSASSIN BLOWBACK PISTOL FLAT DARK EARTH', 'ACTION ARMY', 120, 'https://www.arsenalsports.com/img/17704/produtos/600/f62f04c9989c59a52d454457bf5d2acb.jpg', (SELECT id FROM public.categories WHERE slug = 'pistolas'), 'GBB', 'O primeiro design exclusivo de pistola do Action Army vem com estilo agressivo e desempenho para combinar. Design exclusivo de pistola de alvo, ótimo para plinking de alvo e uso em escaramuças de Airsoft. Modos de disparo semi-automático e totalmente automático selecionáveis! O cano com rosca de 14 mm permite o uso de supressores de Airsoft. Miras de ferro dianteiras e traseiras estilo fibra óptica. Recursos ambidestros e de troca lateral, como o lançamento magnético e a alça de carregamento, otimizam a ergonomia para atiradores destros e canhotos. Usa Magazine GBB compatível com TM g-spec. Trilho acessório de 20 mm montado em cano removível.', 'https://www.arsenalsports.com/produto/action-army-gbb-aap01-assassin-blowback-pistol-flat-dark-earth-17704.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('ACTION ARMY GBB AAP01C ASSASSIN COMPACT BLOWBACK AIRSOFT PISTOL BLACK', 'ACTION ARMY', 120, 'https://www.arsenalsports.com/img/24655/produtos/600/a40ae4880175c539fe0ed3dd34eff8ff.jpg', (SELECT id FROM public.categories WHERE slug = 'pistolas'), 'GBB', 'Bolts ergonomic design and high performance. Blowback gas system allows for semi-automatic and full-auto firing modes.', 'https://www.arsenalsports.com/produto/action-army-gbb-aap01c-assassin-compact-blowback-airsoft-pistol-black-24655.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('ACTION ARMY SPRING SNIPER BOLT ACTION ACC-T10 AIRSOFT RIFLE FLAT DARK EARTH COMBO', 'ACTION ARMY', 299, 'https://www.arsenalsports.com/img/14690/produtos/600/39d85317c63f2c2a58673fe60bf2a92c.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'A Action Army Company (AAC) foi fundada no ano de 2010 e atualmente está localizada em Taiwan. Originalmente, a Action Army Company focou na criação de peças de alto desempenho para a GearBox, mas expandiu a criação de peças externas CNC, como o chassi AAC-21. Action Army tem a capacidade de máquina CNC, die cast, forjar, carimbo, revestimento em pó, etc. suas partes para a maior durabilidade e excelente aparência consistente. Seu objetivo é construir novos produtos com um material muito mais forte, porém mais leve, para obter o máximo de eficiência de sua pistola de airsoft interna e externamente.', 'https://www.arsenalsports.com/produto/action-army-spring-sniper-bolt-action-acct10-airsoft-rifle-flat-dark-earth-combo-14690.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('ACTION ARMY SPRING SNIPER BOLT ACTION ACC-T10 AIRSOFT RIFLE BLACK', 'ACTION ARMY', 299, 'https://www.arsenalsports.com/img/15231/produtos/600/668f44f8649485a582c33adfe909d0d2.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'A Action Army Company (AAC) foi fundada no ano de 2010 e atualmente está localizada em Taiwan. Originalmente, a Action Army Company focou na criação de peças de alto desempenho para a GearBox, mas expandiu a criação de peças externas CNC, como o chassi AAC-21. Action Army tem a capacidade de máquina CNC, die cast, forjar, carimbo, revestimento em pó, etc. suas partes para a maior durabilidade e excelente aparência consistente. Seu objetivo é construir novos produtos com um material muito mais forte, porém mais leve, para obter o máximo de eficiência de sua pistola de airsoft interna e externamente.', 'https://www.arsenalsports.com/produto/action-army-spring-sniper-bolt-action-acct10-airsoft-rifle-black-15231.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM AEG MP44 REAL WOOD WWII AIRSOFT RIFLE BLACK', 'AGM', 320, 'https://www.arsenalsports.com/img/34836/produtos/600/b4c14e16e947ecc87cfaef233e8889aa.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'A AGM MP056B é uma réplica autêntica do fuzil automático alemão StG 44 (MP 44), primorosamente fabricada em metal, que certamente encantará jogadores de airsoft e entusiastas de reconstituições históricas. Feita principalmente de alumínio e aço, oferece qualidade de construção incomparável. O tubo de gás em metal, a cobertura do cano e o espaçoso carregador de alta capacidade para 400 BBs garantem uma experiência de jogo autêntica.

A coronha de madeira, com espaço dedicado para a bateria, contribui para o visual realista e o conforto do usuário. O seletor de modo de disparo horizontal e a possibilidade de ajustar o sistema hop-up abrindo a tampa de ejeção de projéteis são características que tornam esta réplica não apenas visualmente atraente, mas também excepcionalmente funcional e interessante para o entusiasta mais exigente.

- No coração desta réplica da MP 44 está uma robusta gearbox v2, repleta de componentes reforçados que garantem desempenho e durabilidade excepcionais.
- Engrenagens de aço montadas em rolamentos de 8 mm
- Cilindro cromado
- Cabeça do pistão direcional com rolamentos
- Guia de mola de metal
- Magazine de Hi-Cap e até 400 Rounds
- **ACOMPANHA 02 MAGAZINES EXTRAS. TOTALIZANDO 03 MAGAZINES**

**\*As descrições e especificações dos produtos são de responsabilidade do fabricante. Não nos responsabilizamos por imprecisões ou inconsistências nas informações ou imagens exibidas**', 'https://www.arsenalsports.com/produto/agm-aeg-mp44-real-wood-wwii-airsoft-rifle-black-34836.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM SPRING SNIPER L96 AIRSOFT RIFLE BLACK', 'AGM', 120, 'https://www.arsenalsports.com/img/26630/produtos/600/ad7994d04b2c297dd9ffd06e0be45f7e.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'Corpo de polímero moldado por injeção leve e durável, Barril externo de metal de uma peça, Receptor e parafuso de metal, Trilho acessório superior de metal de 20 mm para montagem de óptica, Design de disparo único e ação de ferrolho, Pontos de amarração dianteiros e traseiros, Compatível com sistema APS2, Chassi de atirador ergonômico. ACOMPANHA 01 MAGAZINE EXTRA. TOTALIZANDO 02 MAGAZINES.', 'https://www.arsenalsports.com/produto/agm-spring-sniper-l96-airsoft-rifle-black-26630.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM SPRING SNIPER L96 AIRSOFT RIFLE OD GREEN', 'AGM', 120, 'https://www.arsenalsports.com/img/26631/produtos/600/7cae957b8dd62fc1b4d62bd06554fe4f.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'Corpo de polímero moldado por injeção leve e durável; Barril externo de metal de uma peça; Receptor e parafuso de metal; Trilho acessório superior de metal de 20 mm para montagem de óptica; Design de disparo único e ação de ferrolho; Pontos de amarração dianteiros e traseiros; Compatível com sistema APS2; Chassi de atirador ergonômico; ACOMPANHA 01 MAGAZINE EXTRA. TOTALIZANDO 02 MAGAZINES.', 'https://www.arsenalsports.com/produto/agm-spring-sniper-l96-airsoft-rifle-od-green-26631.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM SPRING SNIPER SVD DRAGUNOV AIRSOFT RIFLE BLACK', 'AGM', 185, 'https://www.arsenalsports.com/img/26632/produtos/600/3d8e08cc7c8285af44ce376eeba21eb0.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'A ação do ferrolho fácil de usar não requer gás ou baterias. O estoque dobrável facilita o transporte e o armazenamento. Construção durável em liga metálica. O trilho lateral permite a montagem de escopos ou suportes de trilho. ACOMPANHA 01 MAGAZINE EXTRA. TOTALIZANDO 02 MAGAZINES.', 'https://www.arsenalsports.com/produto/agm-spring-sniper-svd-dragunov-airsoft-rifle-black-26632.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM SPRING SNIPER SVD DRAGUNOV AIRSOFT RIFLE BLACK & WOOD', 'AGM', 185, 'https://www.arsenalsports.com/img/26633/produtos/600/e88d3b5e75065f96a4b729fdd1d5f9b0.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'A ação do ferrolho fácil de usar não requer gás ou baterias. O estoque dobrável facilita o transporte e o armazenamento. Construção durável em liga metálica. Utiliza polímero com aparência de madeira. O trilho lateral permite a montagem de escopos ou suportes de trilho. ACOMPANHA 01 MAGAZINE EXTRA. TOTALIZANDO 02 MAGAZINES. Potência de até 420 FPS. Comprimento: 920 mm-1180 mm (dobrado/desdobrado). Modo de disparo: Bolt Spring Action. Capacidade do Magazine: 30 Rounds.', 'https://www.arsenalsports.com/produto/agm-spring-sniper-svd-dragunov-airsoft-rifle-black--wood-26633.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM SPRING SNIPER VSR-10 AIRSOFT RIFLE BLACK & WOOD', 'AGM', 110, 'https://www.arsenalsports.com/img/26636/produtos/600/da7d9ddf738d861e78850cecc87d2af1.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'O AGM MP001 é o rifle perfeito para quem deseja entrar no mundo do atirador de Airsoft. Baseado no infame design Tokyo Marui VSR 10, o AGM MP001 está disponível por uma fração do preço, usando peças comparáveis ??no interior. Uma coronha lisa e sólida construída em plástico ABS é resistente, mas leve, e mantém o ferrolho de aço no lugar, tornando todo o rifle muito sólido. O trilho de acessórios integrado de 20 mm é perfeito para montar escopos ou outras ópticas, e o terminal de fixação do bipé instalado está pronto para ser usado assim que sai da caixa. Também estão incluídos dois pontos de montagem da tipoia - um na frente da coronha e outro na parte traseira - o que significa que você está pronto para prender sua tipoia de dois pontos favorita assim que sai da caixa. ACOMPANHA 01 MAGAZINE EXTRA. TOTALIZANDO 02 MAGAZINES.', 'https://www.arsenalsports.com/produto/agm-spring-sniper-vsr10-airsoft-rifle-black--wood-26636.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AGM SPRING SNIPER VSR-10 AIRSOFT RIFLE BLACK', 'AGM', 110, 'https://www.arsenalsports.com/img/26635/produtos/600/fb8578562fd9bdcf23cf753fe3c468fe.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'O AGM MP001 é o rifle perfeito para quem deseja entrar no mundo do atirador de Airsoft. Baseado no infame design Tokyo Marui VSR 10, o AGM MP001 está disponível por uma fração do preço, usando peças comparáveis ??no interior. Uma coronha lisa e sólida construída em plástico ABS é resistente, mas leve, e mantém o ferrolho de aço no lugar, tornando todo o rifle muito sólido. O trilho de acessórios integrado de 20 mm é perfeito para montar escopos ou outras ópticas, e o terminal de fixação do bipé instalado está pronto para ser usado assim que sai da caixa. Também estão incluídos dois pontos de montagem da tipoia - um na frente da coronha e outro na parte traseira - o que significa que você está pronto para prender sua tipoia de dois pontos favorita assim que sai da caixa. ACOMPANHA 01 MAGAZINE EXTRA. TOTALIZANDO 02 MAGAZINES.', 'https://www.arsenalsports.com/produto/agm-spring-sniper-vsr10-airsoft-rifle-black-26635.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-003 CARBINE AIRSOFT RIFLE BLACK', 'AMOEBA', 99, 'https://www.arsenalsports.com/img/13306/produtos/600/6d6e26874d226f4d20b29effa3721a9e.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Uma série das mais recentes AM-003 de Amoeba Airsoft é baseada em um design bem conhecido de rifles de asHop Up AR, mas essas AM-003s foram consideravelmente modificadas e enriquecidas com muitos detalhes de construção e soluções técnicas interessantes, que melhoram não apenas sua funcionalidade, mas também sua aparência. Graças às suas dimensões compactas, o AM-001 é muito útil e constitui uma ferramenta perfeita durante as ações do airsoft CQB.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am003-carbine-airsoft-rifle-black-13306.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-003 CARBINE AIRSOFT RIFLE DESERT', 'AMOEBA', 99, 'https://www.arsenalsports.com/img/13307/produtos/600/bb61445bd49ab79b4a1506aa4e58448e.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Uma série das mais recentes AM-003 de Amoeba Airsoft é baseada em um design bem conhecido de rifles de asHop Up AR, mas essas AM-003s foram consideravelmente modificadas e enriquecidas com muitos detalhes de construção e soluções técnicas interessantes, que melhoram não apenas sua funcionalidade, mas também sua aparência. Graças às suas dimensões compactas, o AM-001 é muito útil e constitui uma ferramenta perfeita durante as ações do airsoft CQB.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am003-carbine-airsoft-rifle-desert-13307.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG AM-007 M4 CCR AIRSOFT RIFLE DESERT', 'AMOEBA', 0, 'https://www.arsenalsports.com/img/18823/produtos/600/5fe1d6e3c1cabbf99bf81a2224436697.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Construído a partir de material de polímero reforçado extremamente resistente. O design compacto é perfeito para CQB. Punho de pistola texturizado, estoque ajustável, fácil acesso ao compartimento da bateria, visão frontal e traseira removível, botão de liberação de magazine ampliado para fácil uso. GearBox totalmente metálica com partes internas reforçadas. Sistema de controle eletrônico de disparo exclusivo do ARES (EFCS - Safe / Semi / 3rd Burst / Full Auto). Caixa de velocidades programável através da unidade de programação EFCS (vendida separadamente). Receptor de topo plano para óptica e acessórios montados em Picatinny / Weaver de 20 mm. HandGuard RIS de polímero de alto impacto. Alça vertical incluída.', 'https://www.arsenalsports.com/produto/amoeba-aeg-am007-m4-ccr-airsoft-rifle-desert-18823.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-007 CCR AIRSOFT RIFLE BLACK', 'AMOEBA', 159, 'https://www.arsenalsports.com/img/28641/produtos/600/6ae0e8e1252dfa534b983def46f52cf8.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Construído a partir de material de polímero reforçado extremamente resistente. O design compacto é perfeito para CQB. Punho de pistola texturizado. Estoque ajustável. Fácil acesso ao compartimento da bateria. Visão frontal e traseira removível. Botão de liberação de Magazine ampliado para fácil uso. GearBox totalmente metálica com partes internas reforçadas. Sistema de controle eletrônico de disparo exclusivo do ARES (EFCS - Safe / Semi / 3rd Burst / Full Auto). Caixa de velocidades programável através da unidade de programação EFCS (vendida separadamente). Receptor de topo plano para óptica e acessórios montados em Picatinny / Weaver de 20 mm. HandGuard RIS de polímero de alto impacto. Alça vertical incluída.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am007-ccr-airsoft-rifle-black-28641.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-009 13" CARBINE AIRSOFT RIFLE DESERT', 'AMOEBA', 0, 'https://www.arsenalsports.com/img/10036/produtos/600/9cc33aeebd03a4e26bd223ee0a276aaf.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Esse Rifle de Airsoft vem com um sistema de mola de troca rápida, permitindo assim que você atualize ou reduza rapidamente o FPS (Pés por segundo) da sua arma com facilidade.

Este rifle estilo AMOEBA faz parte do novo sistema de GearBox EFCS da ARES (Electronic Firing Control System), pois permite que a GearBox seja programada para ser Semi, 3 round burst ou full auto usando o Programador Ares Amoeba Electronic Gearbox Programmer EFCS.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am009-13-carbine-airsoft-rifle-desert-10036.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-008 CARBINE AIRSOFT RIFLE DESERT', 'AMOEBA', 200, 'https://www.arsenalsports.com/img/33274/produtos/600/72c2eb23b5d41cf356d73d43ad5026cb.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Construído com material de polímero reforçado extremamente resistente. O design compacto é perfeito para CQB. Punho de pistola texturizado. Estoque de crane ajustável. Vista frontal virada para cima, visão traseira removível. Botão de liberação de Magazine ampliado para facilitar o uso. Sistema eletrônico de controle de queima eletrônico exclusivo da ARES (EFCS - Safe / Semi / 3rd Burst / Full Auto). GearBox programável via unidade de programação EFCS (vendida separadamente). 

Especificações:
- BlowBack: Não
- Comprimento: 670mm - 750mm
- Peso: 2080 Gramas
- Material: Metal e Polímero
- Potência de até 380 FPS
- Modo de Disparo: Safe, Semi-Auto, Full-Auto
- GearBox: Ver. 2 Modificada
- Hop-Up: Ajustável
- Capacidade do Magazine: 300 Rounds
- MOSFET/ETU: Sim
- Quick Spring Change System: Sim', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am008-carbine-airsoft-rifle-desert-33274.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-013 12" CARBINE AIRSOFT RIFLE DESERT', 'AMOEBA', 249, 'https://www.arsenalsports.com/img/7703/produtos/600/f662f5c9993c66d531b056e793bdb6a5.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Construído a partir de polímero reforçado com fibra de nylon incrivelmente resistente. Handguard de alumínio CNC 6063 com duas seções de trilho Picatinny e duas paradas de mão. Supressor simulado de alumínio montado no handguard. Design compacto é perfeito para CQB.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am013-12-carbine-airsoft-rifle-desert-7703.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 MUTANT AMM5 AIRSOFT RIFLE BLACK', 'AMOEBA', 219, 'https://www.arsenalsports.com/img/17952/produtos/600/6420324d0c6ba8026907072c17e87f77.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Tipo AEG, GearBox EFCS, Material de fibra de nylon, alumínio, metal, Tipo de Disparo: Fire Mode Totalmente Automático / Semi Auto / Seguro (O Fire Mode pode ser personalizado pelo Programador de GearBox Eletrônica), Material da GearBox liga de zine fundido, Hop-Up ajustável, Magazine: 140 Rounds, Liberação Rápida de Mola, Tipos de bateria: 7,4v - 11,1v, Peso 2120g, Comprimento 520-615 mm. VEM COM 01 MAGAZINE 140 ROUNDS MID-CAP.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-mutant-amm5-airsoft-rifle-black-17952.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 AM-015 CARBINE AIRSOFT RIFLE BLACK', 'AMOEBA', 249, 'https://www.arsenalsports.com/img/10037/produtos/600/e1a251855f860fc69e81286bda826a87.png', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Tanto o rifle quanto o calibre utilizados foram desenvolvidos em estreita cooperação com unidades de operações especiais americanas para criar um substituto adequado e eficaz para o HK MP5 e sistemas de armas CQB similares. O rifle é projetado para ser muito conveniente para uso militar, onde a plataforma CAR-15 é emitida e de uso comum, já que muitas similaridades existiriam nos controles de fogo, manipulação de armas e magazines. Finalmente, a versão de airsoft chegou. Muitas pessoas foram e personalizaram sua própria versão, mas a ARES é a única empresa que ouviu e partiu para projetar o AM-015, que se assemelhava muito ao AAC Badger PDW da AAC. Ele se encaixa com a linha Amoeba, já que o receptor não mudou, mas eles conseguiram adicionar o elegante estoque extensível HB, um HandGuard de flutuação livre e um amplificador saindo da frente. O HandGuard é um pouco mais curto, adequado para quem prefere o comprimento da arma menor. Funciona com o Programador de Caixa de Velocidades Eletrônico (EFCS) ARES / Amoeba para a GearBox do Sistema de Controle de Acionamento Eletrônico ARES, para que você possa configurar o seu AEG para explodir fogo, se preferir. A resposta do acionador é excelente e funciona melhor com uma bateria de 7,4V PEQ que é armazenada em um pequeno compartimento do material. É um pouco inquieto, mas se encaixa perfeitamente para que você não fique chocado.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-am015-carbine-airsoft-rifle-black-10037.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 MUTANT AMM7 AIRSOFT RIFLE DESERT', 'AMOEBA', 219, 'https://www.arsenalsports.com/img/17955/produtos/600/cc3f363e1c84adcf8c1e30ea308e7ee1.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Série AMOEBA M4 redesenhada, receptor superior e inferior robusto e leve em polímero, guarda-mão M-LOK de liberação rápida em alumínio CNC, comprimentos de cano e guarda-mão altamente configuráveis.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-mutant-amm7-airsoft-rifle-desert-17955.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA AEG M4 MUTANT AMM9 AIRSOFT RIFLE BLACK', 'AMOEBA', 219, 'https://www.arsenalsports.com/img/17956/produtos/600/3c4ac25dbcf1f86c13dfdbaebd562692.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'AEG', 'Tipo AEG, GearBox EFCS, Material de fibra de nylon, alumínio, metal, Tipo de Disparo: Fire Mode Totalmente Automático / Semi Auto / Seguro, Material da GearBox liga de zine fundido, Hop-Up ajustável, Magazine: 140 Rounds, Liberação Rápida de Mola, Tipos de bateria: 7,4v - 11,1v, Peso 2440g, Comprimento 680-750mm. VEM COM 01 MAGAZINE 140 ROUNDS MID-CAP.', 'https://www.arsenalsports.com/produto/amoeba-aeg-m4-mutant-amm9-airsoft-rifle-black-17956.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER AS01 AIRSOFT RIFLE BLACK', 'AMOEBA', 148, 'https://www.arsenalsports.com/img/11364/produtos/600/535451a4452e25d1a2baa5695a20026e.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'O rifle sniper AMOEBA Striker S1 é um rifle Airsoft avançado, compacto e de precisão projetado em torno dos conceitos de modularidade, funcionalidade e minimalismo. Com todos os recursos úteis que você precisa e quer, e nenhum dos sinos e assobios que um Sniper Airsoft não quer, o AMOEBA S1 sai da caixa pronto para lutar. Construído sobre a base de um chassi de polímero modular que apresenta um estoque ajustável, riser e grip, o atacante S1 pode ser personalizado para se adequar ao atirador individual.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-as01-airsoft-rifle-black-11364.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER AS01 AIRSOFT RIFLE DESERT', 'AMOEBA', 148, 'https://www.arsenalsports.com/img/11365/produtos/600/5fb4ac4f8ec7e2954eb40f5527d1c780.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'O rifle sniper AMOEBA Striker S1 é um rifle Airsoft avançado, compacto e de precisão projetado em torno dos conceitos de modularidade, funcionalidade e minimalismo. Com todos os recursos úteis que você precisa e quer, e nenhum dos sinos e assobios que um Sniper Airsoft não quer, o AMOEBA S1 sai da caixa pronto para lutar. Construído sobre a base de um chassi de polímero modular que apresenta um estoque ajustável, riser e grip, o atacante S1 pode ser personalizado para se adequar ao atirador individual.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-as01-airsoft-rifle-desert-11365.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER AS01 AIRSOFT RIFLE URBAN GREY', 'AMOEBA', 148, 'https://www.arsenalsports.com/img/11700/produtos/600/531e6f8d9dc5b81c36471c5e28f623c4.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'O rifle sniper AMOEBA Striker S1 é um rifle Airsoft avançado, compacto e de precisão projetado em torno dos conceitos de modularidade, funcionalidade e minimalismo. Com todos os recursos úteis que você precisa e quer, e nenhum dos sinos e assobios que um Sniper Airsoft não quer, o AMOEBA S1 sai da caixa pronto para lutar. Construído sobre a base de um chassi de polímero modular que apresenta um estoque ajustável, riser e grip, o atacante S1 pode ser personalizado para se adequar ao atirador individual. O receptor de metal abriga o Compact Power Bolt da AMOEBA, que fornece ao atirador a mesma potência com a qual ele está acostumado, com um comprimento de tração muito mais curto.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-as01-airsoft-rifle-urban-grey-11700.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER AS01 AIRSOFT RIFLE OD GREEN', 'AMOEBA', 148, 'https://www.arsenalsports.com/img/11531/produtos/600/c794b017bb6362642eabb518b03c0e03.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'O rifle sniper AMOEBA Striker S1 é um rifle Airsoft avançado, compacto e de precisão projetado em torno dos conceitos de modularidade, funcionalidade e minimalismo. Com todos os recursos úteis que você precisa e quer, e nenhum dos sinos e assobios que um Sniper Airsoft não quer, o AMOEBA S1 sai da caixa pronto para lutar.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-as01-airsoft-rifle-od-green-11531.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER AS03 AIRSOFT RIFLE BLACK', 'AMOEBA', 109, 'https://www.arsenalsports.com/img/16148/produtos/600/aefd419411cf75bd477a2a6a7909e424.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'A terceira iteração do famoso rifle sniper STRIKER chega até nós em uma configuração de "pistola" ultra compacta. Esta pistola apresenta a mesma ação de golpe curto encontrada nas gerações anteriores e se baseia na ação aprimorada encontrada no STRIKER 02. Embora seu formato ultra compacto possa ser incomum, ele ainda possui precisão excepcional e toda a modularidade encontrada nas armas anteriores. Seu corpo de polímero leve torna muito leve; de fato, esta pistola pode ser disparada com as mãos, excelente para uma segunda ou terceira opção quando é necessário um único tiro de precisão.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-as03-airsoft-rifle-black-16148.html', true, 25, 20, 3);
