INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER AS03 AIRSOFT RIFLE URBAN GREY', 'AMOEBA', 109, 'https://www.arsenalsports.com/img/15798/produtos/600/d6357091d12786bb1ea2c5b34394b2d6.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'A terceira iteração do famoso rifle sniper STRIKER chega até nós em uma configuração ''pistola'' ultracompacta. Esta arma possui a mesma ação de curto curso encontrada nas gerações anteriores e se baseia na ação aprimorada encontrada no STRIKER 02. Embora seu formato ultracompacto possa ser incomum, ele ainda possui precisão excepcional e toda a modularidade encontrada nas armas anteriores. Seu corpo de polímero leve torna muito leve, na verdade, esta arma pode ser atirada de mãos dadas, excelente para uma segunda ou terceira opção quando é necessário um único tiro de precisão para ser levado.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-as03-airsoft-rifle-urban-grey-15798.html', true, 25, 20, 3);
INSERT INTO public.products (name, brand, usd_price, image_url, category_id, system, description, source_url, is_available, tax_importer, tax_admin, tax_nf) VALUES ('AMOEBA SPRING SNIPER STRIKER T01 AIRSOFT RIFLE BLACK', 'AMOEBA', 155, 'https://www.arsenalsports.com/img/18824/produtos/600/eaea01c0467c7955decd3c48a80634be.jpg', (SELECT id FROM public.categories WHERE slug = 'rifles'), 'Spring', 'Alça de carregamento de baixo perfil, Botão de lançamento de nova Magazine, G2 (Geração 2) Receptor superior: 90 graus Sear, Trilho superior de comprimento total, Pino de bolt fixo, Segurança Avançada, Gatilho Totalmente Ajustável, O carregamento é bloqueado quando a segurança está ativada, Estoque de fundo tático totalmente ajustável com Magwell sobressalente, Peça de bochecha ajustável e almofada de bochecha, Novo Indicador de Carga, Compatível com peças AS Series.', 'https://www.arsenalsports.com/produto/amoeba-spring-sniper-striker-t01-airsoft-rifle-black-18824.html', true, 25, 20, 3);
